import { Chess, type Move, type Square } from 'chess.js'
import { useCallback, useRef, useState } from 'react'
import { ApiError, postMove } from '../apiClient'

export type Color = 'white' | 'black'
export type HistoryEntry = { uci: string; san: string }
export type PendingPromotion = { from: Square; to: Square }
export type PromotionPiece = 'q' | 'r' | 'b' | 'n'

export type PieceDropArgs = {
  sourceSquare: string
  targetSquare: string | null
}

export type ChessSession = {
  fen: string
  history: HistoryEntry[]
  isGameOver: boolean
  awaiting: boolean
  error: ApiError | null
  humanColor: Color
  canDrag: boolean
  pendingPromotion: PendingPromotion | null
  onPieceDrop: (args: PieceDropArgs) => boolean
  resolvePromotion: (piece: PromotionPiece) => void
  cancelPromotion: () => void
}

export type UseChessSessionOptions = {
  humanColor: Color
  // Optional starting FEN — defaults to the chess starting position. Used by
  // tests with pre-promotion / pre-terminal fixtures; production callers leave
  // it unset.
  initialFen?: string
}

export function useChessSession(options: UseChessSessionOptions): ChessSession {
  // humanColor='black' deferred to Phase 3 / issue #05: engine must move first,
  // board orientation flips, and the color-selection UI ships together as one
  // coherent slice. Guard rather than silently behaving as white.
  if (options.humanColor === 'black') {
    throw new Error(
      "useChessSession: humanColor='black' is not implemented in Phase 2 (deferred to Phase 3 / issue #05).",
    )
  }

  const chessRef = useRef<Chess>(new Chess(options.initialFen))
  // Monotonic id so a late-arriving /move response from a prior turn cannot
  // overwrite state for the current turn (defensive against any race the input
  // lock might miss; e.g. rollback-then-new-move while the prior request is
  // still in flight).
  const requestIdRef = useRef(0)

  const [fen, setFen] = useState(chessRef.current.fen())
  const [history, setHistory] = useState<HistoryEntry[]>([])
  const [awaiting, setAwaiting] = useState(false)
  const [isGameOver, setIsGameOver] = useState(false)
  const [error, setError] = useState<ApiError | null>(null)
  const [pendingPromotion, setPendingPromotion] = useState<PendingPromotion | null>(null)

  const canDrag = !awaiting && !isGameOver && pendingPromotion === null

  const requestEngineMove = useCallback(async (currentFen: string) => {
    const id = ++requestIdRef.current
    setAwaiting(true)
    setError(null)

    let response: Awaited<ReturnType<typeof postMove>>
    try {
      response = await postMove(currentFen)
    } catch (e) {
      if (id !== requestIdRef.current) return
      const apiErr = e instanceof ApiError ? e : new ApiError(0, String(e))
      // Invariant 6 (422 defensive): trust local chess.isGameOver(). If the
      // user's move was actually terminal, freeze. Otherwise treat as a
      // genuine failure and roll back (Invariant 5).
      if (chessRef.current.isGameOver()) {
        setIsGameOver(true)
        setAwaiting(false)
        return
      }
      setFen(chessRef.current.fen())
      setHistory((h) => h.slice(0, -1))
      setError(apiErr)
      setAwaiting(false)
      return
    }
    if (id !== requestIdRef.current) return

    const uci = response.move_uci
    const from = uci.slice(0, 2)
    const to = uci.slice(2, 4)
    const promotion = uci.length === 5 ? uci[4] : undefined

    let mv: Move
    try {
      mv = chessRef.current.move({ from, to, promotion })
    } catch {
      chessRef.current.undo()
      setFen(chessRef.current.fen())
      setHistory((h) => h.slice(0, -1))
      setError(new ApiError(0, `engine returned illegal move "${uci}"`))
      setAwaiting(false)
      return
    }

    setHistory((h) => [...h, { uci, san: mv.san }])
    setFen(chessRef.current.fen())
    // Invariant 4: re-check terminal state after the engine's reply.
    if (chessRef.current.isGameOver()) setIsGameOver(true)
    setAwaiting(false)
  }, [])

  const commitUserMove = useCallback(
    (uci: string, mv: Move) => {
      setHistory((h) => [...h, { uci, san: mv.san }])
      const newFen = chessRef.current.fen()
      setFen(newFen)
      // Invariant 2: check terminal state BEFORE POST. If the user's move
      // ended the game (checkmate, stalemate, etc.) the engine has no legal
      // reply — POSTing would just earn a 422.
      if (chessRef.current.isGameOver()) {
        setIsGameOver(true)
        return
      }
      void requestEngineMove(newFen)
    },
    [requestEngineMove],
  )

  const onPieceDrop = useCallback(
    ({ sourceSquare, targetSquare }: PieceDropArgs): boolean => {
      // Invariant 3: sync-reject when locked. react-chessboard also gates
      // drags via canDragPiece, but onPieceDrop is the authoritative gate
      // because the user could still drop a piece that started dragging
      // before the lock engaged.
      if (!canDrag || targetSquare === null) return false

      const from = sourceSquare as Square
      const to = targetSquare as Square

      const promotionCandidate = chessRef.current
        .moves({ square: from, verbose: true })
        .find((m) => m.to === to && m.promotion !== undefined)
      if (promotionCandidate) {
        // Hold the move pending the picker. chess.js is NOT mutated yet —
        // cancel just clears the pending state, no undo needed.
        setPendingPromotion({ from, to })
        return false
      }

      let mv: Move
      try {
        mv = chessRef.current.move({ from, to })
      } catch {
        return false
      }
      commitUserMove(`${from}${to}`, mv)
      return true
    },
    [canDrag, commitUserMove],
  )

  const resolvePromotion = useCallback(
    (piece: PromotionPiece) => {
      if (!pendingPromotion) return
      const { from, to } = pendingPromotion
      let mv: Move
      try {
        mv = chessRef.current.move({ from, to, promotion: piece })
      } catch {
        setPendingPromotion(null)
        return
      }
      setPendingPromotion(null)
      commitUserMove(`${from}${to}${piece}`, mv)
    },
    [pendingPromotion, commitUserMove],
  )

  const cancelPromotion = useCallback(() => {
    setPendingPromotion(null)
  }, [])

  return {
    fen,
    history,
    isGameOver,
    awaiting,
    error,
    humanColor: options.humanColor,
    canDrag,
    pendingPromotion,
    onPieceDrop,
    resolvePromotion,
    cancelPromotion,
  }
}

import { act, renderHook, waitFor } from '@testing-library/react'
import { Chess } from 'chess.js'
import { afterEach, describe, expect, it, vi } from 'vitest'
import { useChessSession } from './useChessSession'

const STARTING_FEN = 'rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1'
// White pawn on a7, black pawn on a2 — both sides have non-king material so
// the post-promotion position is NOT insufficient-material terminal. White to
// move can promote on a8 to Q/R/B/N. No checks.
const PRE_PROMOTION_FEN = '4k3/P7/8/8/8/8/p7/4K3 w - - 0 1'

function mockFetchOk(body: unknown): ReturnType<typeof vi.spyOn> {
  return vi.spyOn(globalThis, 'fetch').mockResolvedValueOnce(
    new Response(JSON.stringify(body), {
      status: 200,
      headers: { 'Content-Type': 'application/json' },
    }),
  )
}

describe("useChessSession ({ humanColor: 'white' })", () => {
  afterEach(() => {
    vi.restoreAllMocks()
  })

  it('initializes to the starting position with the user to move', () => {
    const { result } = renderHook(() => useChessSession({ humanColor: 'white' }))

    expect(result.current.fen).toBe(STARTING_FEN)
    expect(result.current.history).toEqual([])
    expect(result.current.isGameOver).toBe(false)
    expect(result.current.awaiting).toBe(false)
    expect(result.current.error).toBeNull()
    expect(result.current.humanColor).toBe('white')
    expect(result.current.canDrag).toBe(true)
    expect(result.current.pendingPromotion).toBeNull()
  })

  it('applies a user move, POSTs /move, and applies the engine reply', async () => {
    // Engine plays a quiet reply (e7-e5) to the user's e2-e4.
    const fetchSpy = mockFetchOk({ move_uci: 'e7e5' })

    const { result } = renderHook(() => useChessSession({ humanColor: 'white' }))

    let dropAccepted = false
    act(() => {
      dropAccepted = result.current.onPieceDrop({
        sourceSquare: 'e2',
        targetSquare: 'e4',
      })
    })
    expect(dropAccepted).toBe(true)

    await waitFor(() => expect(result.current.awaiting).toBe(false))

    const expectedPostFen = new Chess()
    expectedPostFen.move({ from: 'e2', to: 'e4' })
    expect(fetchSpy).toHaveBeenCalledTimes(1)
    const [, init] = fetchSpy.mock.calls[0] as [string, RequestInit]
    expect(JSON.parse(init.body as string)).toEqual({ fen: expectedPostFen.fen() })

    expect(result.current.history.map((h) => h.uci)).toEqual(['e2e4', 'e7e5'])
    expect(result.current.history.map((h) => h.san)).toEqual(['e4', 'e5'])
    expect(result.current.error).toBeNull()
    expect(result.current.isGameOver).toBe(false)
  })

  it('shows the promotion picker, applies the chosen piece, and POSTs the post-promotion FEN', async () => {
    const fetchSpy = mockFetchOk({ move_uci: 'e8d8' }) // some legal black king move post-promotion

    const { result } = renderHook(() =>
      useChessSession({ humanColor: 'white', initialFen: PRE_PROMOTION_FEN }),
    )

    // 1. Pawn drop to last rank → picker pending, no fetch yet.
    let dropAccepted = false
    act(() => {
      dropAccepted = result.current.onPieceDrop({
        sourceSquare: 'a7',
        targetSquare: 'a8',
      })
    })
    expect(dropAccepted).toBe(false)
    expect(result.current.pendingPromotion).toEqual({ from: 'a7', to: 'a8' })
    expect(result.current.canDrag).toBe(false)
    expect(fetchSpy).not.toHaveBeenCalled()
    // chess.js itself is NOT mutated until the picker resolves.
    expect(result.current.fen).toBe(PRE_PROMOTION_FEN)

    // 2. User picks knight (under-promotion).
    act(() => {
      result.current.resolvePromotion('n')
    })

    // After resolvePromotion, the move is applied locally and the POST fires.
    await waitFor(() => expect(fetchSpy).toHaveBeenCalledTimes(1))

    // FEN POSTed must reflect the knight promotion.
    const [, init] = fetchSpy.mock.calls[0] as [string, RequestInit]
    const postedFen = (JSON.parse(init.body as string) as { fen: string }).fen
    const verify = new Chess(PRE_PROMOTION_FEN)
    verify.move({ from: 'a7', to: 'a8', promotion: 'n' })
    expect(postedFen).toBe(verify.fen())
    expect(postedFen).toContain('N3k3') // a8=N, e8=k on rank 8

    await waitFor(() => expect(result.current.awaiting).toBe(false))

    expect(result.current.history.map((h) => h.uci)).toEqual(['a7a8n', 'e8d8'])
    expect(result.current.history[0]?.san).toMatch(/=N/) // SAN includes promotion piece
    expect(result.current.pendingPromotion).toBeNull()
    expect(result.current.error).toBeNull()
  })

  it('cancelPromotion clears the pending picker without POSTing', () => {
    const fetchSpy = vi.spyOn(globalThis, 'fetch')

    const { result } = renderHook(() =>
      useChessSession({ humanColor: 'white', initialFen: PRE_PROMOTION_FEN }),
    )

    act(() => {
      result.current.onPieceDrop({ sourceSquare: 'a7', targetSquare: 'a8' })
    })
    expect(result.current.pendingPromotion).not.toBeNull()

    act(() => {
      result.current.cancelPromotion()
    })

    expect(result.current.pendingPromotion).toBeNull()
    expect(result.current.fen).toBe(PRE_PROMOTION_FEN)
    expect(result.current.canDrag).toBe(true)
    expect(fetchSpy).not.toHaveBeenCalled()
  })
})

describe("useChessSession ({ humanColor: 'black' })", () => {
  it('throws — engine-moves-first lifecycle ships in Phase 3 / issue #05', () => {
    expect(() => renderHook(() => useChessSession({ humanColor: 'black' }))).toThrow(/Phase 2/)
  })
})
